export const App: React.FC = () => {
    const [clients, setClients] = useState<Client[]>([]);
    const [archive, setArchive] = useState<Client[]>([]);
    const [masters, setMasters] = useState<Master[]>([]);
    const [headers, setHeaders] = useState<string[]>([]);
    const [templates, setTemplates] = useState<MessageTemplate[]>([]);
    const [settings, setSettings] = useState<SettingsType>(getInitialSettings);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [toasts, setToasts] = useState<ToastMessage[]>([]);
    const [savedViews, setSavedViews] = useState<SavedView[]>(() => {
        try {
            return JSON.parse(localStorage.getItem('saved_views') || '[]');
        } catch { return []; }
    });

    const addToast = (message: string, type: 'success' | 'error') => {
        const id = Date.now().toString();
        const duration = type === 'error' ? 0 : 4000;
        setToasts(prev => [...prev, { id, message, type, duration }]);
    };

    const removeToast = (id: string) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    };

    const handleSaveViews = (views: SavedView[]) => {
        setSavedViews(views);
        localStorage.setItem('saved_views', JSON.stringify(views));
    };

    const fetchData = useCallback(async () => {
        if (!settings.googleSheetId) {
            setIsLoading(false);
            return;
        }

        setIsLoading(true);
        setError(null);
        try {
            const [clientsData, templatesData, mastersData] = await Promise.all([
                api.fetchClients(),
                api.fetchTemplates(),
                api.fetchMasters(),
            ]);

            setClients(clientsData.clients);
            setArchive(clientsData.archive);
            setHeaders(clientsData.headers);
            setTemplates(templatesData);
            setMasters(mastersData);

        } catch (err: any) {
            console.error(err);
            setError(err.message || 'Ошибка загрузки данных');
            addToast(`Ошибка загрузки: ${err.message}`, 'error');
        } finally {
            setIsLoading(false);
        }
    }, [settings.googleSheetId]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleSaveSettings = () => {
        const newSettings = getInitialSettings();
        setSettings(newSettings);
    };

    if (!settings.googleSheetId) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex items-center justify-center p-4">
                <div className="max-w-md w-full">
                    <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg overflow-hidden">
                        <div className="p-6">
                            <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4">Настройка CRM</h2>
                            <p className="text-gray-600 dark:text-gray-300 mb-6 text-sm">
                                Для начала работы необходимо указать URL веб-приложения Google Apps Script.
                            </p>
                            <Settings 
                                initialSettings={settings} 
                                initialTemplates={templates}
                                initialMasters={masters}
                                clients={clients}
                                onSave={handleSaveSettings}
                                needsSetup={true}
                            />
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <HashRouter>
            <div className="flex min-h-screen bg-gray-100 dark:bg-gray-900 text-gray-900 dark:text-gray-100">
                <ToastContainer toasts={toasts} removeToast={removeToast} />

                <aside className="hidden md:flex w-64 flex-col bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 fixed inset-y-0 z-50">
                    <div className="flex items-center justify-between h-16 px-6 border-b border-gray-200 dark:border-gray-700">
                        <span className="text-xl font-bold text-primary-600 dark:text-primary-400">CRM OtelShun</span>
                    </div>

                    <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
                        <NavItem to="/" icon={<DashboardIcon />} label="Дашборд" />
                        <NavItem to="/clients" icon={<ClientsIcon />} label="Клиенты" />
                        <NavItem to="/masters" icon={<MastersIcon />} label="Мастера" />
                        <NavItem to="/settings" icon={<SettingsIcon />} label="Настройки" />
                    </nav>

                    <div className="p-4 border-t border-gray-200 dark:border-gray-700 space-y-4">
                        <Link to="/add-client" className="flex items-center justify-center gap-2 w-full py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors font-medium text-sm shadow-sm">
                             <PlusCircleIcon /> Новый клиент
                        </Link>
                        <div className="flex items-center justify-between">
                             <ThemeSwitcher />
                             <div className="text-xs text-gray-400">v3.4.5</div>
                        </div>
                    </div>
                </aside>

                <div className="md:hidden fixed bottom-0 inset-x-0 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 z-50 pb-safe">
                    <div className="flex justify-around items-center h-16 px-2">
                        <Link to="/" className="flex flex-col items-center justify-center w-full h-full text-gray-500 dark:text-gray-400 hover:text-primary-600 dark:hover:text-primary-400">
                            <DashboardIcon />
                            <span className="text-[10px] mt-1">Главная</span>
                        </Link>
                        <Link to="/clients" className="flex flex-col items-center justify-center w-full h-full text-gray-500 dark:text-gray-400 hover:text-primary-600 dark:hover:text-primary-400">
                            <ClientsIcon />
                            <span className="text-[10px] mt-1">Клиенты</span>
                        </Link>
                         <Link to="/add-client" className="flex flex-col items-center justify-center w-full h-full">
                            <div className="w-10 h-10 bg-primary-600 rounded-full flex items-center justify-center text-white shadow-lg -mt-6 border-4 border-gray-100 dark:border-gray-900">
                                <PlusCircleIcon className="w-6 h-6"/>
                            </div>
                            <span className="text-[10px] mt-1 font-medium text-primary-600 dark:text-primary-400">Создать</span>
                        </Link>
                        <Link to="/masters" className="flex flex-col items-center justify-center w-full h-full text-gray-500 dark:text-gray-400 hover:text-primary-600 dark:hover:text-primary-400">
                            <MastersIcon />
                            <span className="text-[10px] mt-1">Мастера</span>
                        </Link>
                        <Link to="/settings" className="flex flex-col items-center justify-center w-full h-full text-gray-500 dark:text-gray-400 hover:text-primary-600 dark:hover:text-primary-400">
                            <SettingsIcon />
                            <span className="text-[10px] mt-1">Меню</span>
                        </Link>
                    </div>
                </div>

                <main className="flex-1 md:ml-64 pb-16 md:pb-0 min-h-screen">
                    <header className="hidden md:flex h-16 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 items-center justify-between px-6 sticky top-0 z-30">
                        <h1 className="text-xl font-semibold text-gray-800 dark:text-white">
                            CRM Система хранения шин
                        </h1>
                        <div className="flex items-center gap-4">
                            {isLoading && <span className="text-sm text-gray-500 animate-pulse">Загрузка данных...</span>}
                            {error && <span className="text-sm text-red-500">Ошибка!</span>}
                        </div>
                    </header>

                    <div className="h-full">
                        {isLoading && clients.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-[80vh]">
                                <div className="w-12 h-12 border-4 border-primary-200 border-t-primary-600 rounded-full animate-spin mb-4"></div>
                                <p className="text-gray-500 dark:text-gray-400">Загрузка CRM...</p>
                            </div>
                        ) : (
                            <Routes>
                                <Route path="/" element={<Dashboard clients={clients} archive={archive} templates={templates} />} />
                                <Route path="/clients" element={
                                    <ClientsView 
                                        clients={clients} 
                                        headers={headers} 
                                        templates={templates} 
                                        savedViews={savedViews} 
                                        onSaveViews={handleSaveViews}
                                        refreshData={fetchData} 
                                    />
                                } />
                                <Route path="/clients/:id" element={
                                    <ClientDetailsPage 
                                        clients={clients} 
                                        headers={headers} 
                                        templates={templates} 
                                        refreshData={fetchData} 
                                        settings={settings}
                                    />
                                } />
                                <Route path="/add-client" element={<AddClient settings={settings} onClientAdd={fetchData} />} />
                                <Route path="/masters" element={<MastersView masters={masters} setMasters={setMasters} clients={clients} />} />
                                <Route path="/settings" element={
                                    <Settings 
                                        initialSettings={settings} 
                                        initialTemplates={templates}
                                        initialMasters={masters}
                                        clients={clients}
                                        onSave={handleSaveSettings}
                                        needsSetup={false}
                                    />
                                } />
                                <Route path="*" element={<Navigate to="/" replace />} />
                            </Routes>
                        )}
                    </div>
                </main>
            </div>
        </HashRouter>
    );
};
